	void prosesMrpl(Statement stmt,boolean hasilExe,String filing_timeRPL) throws SQLException {
		rpl="";
		if (!hasilExe) {
			System.out.println("not hasilExe");
			int updateCount=stmt.getUpdateCount();
			System.out.println(updateCount);
		} else {
			ResultSet rs=stmt.getResultSet();
			while (rs.next()) {
				if (rs.getString("priority")!=null) {
					rpl+=rs.getString("priority");
				}
				for (int iCnt=1;iCnt<22;iCnt++) {
					String sDest="destination";
					sDest+=Integer.toString(iCnt);
					if (rs.getString(sDest)!=null) {
						if (rs.getString(sDest).compareTo("")!=0) {
							rpl+=" "; 
							rpl+=rs.getString(sDest);
							if ((iCnt==7) || (iCnt==14)) rpl+="\n";
						}
					}
				}
				rpl+="\n";
				if (filing_timeRPL!=null) {rpl+=filing_timeRPL;rpl+=" ";}
				if (rs.getString("originator")!=null) rpl+=rs.getString("originator");
				rpl+="\n";
				//message
				rpl+="(FPL";

				//type7
				if (rs.getString("L_aircraft_id")!=null) {rpl+="-"+rs.getString("L_aircraft_id");}
				
				//type9
				boolean flgr=false;
				if (rs.getString("M_type_aircraft")!=null) {
					rpl+="\n-"+rs.getString("M_type_aircraft");
					flgr=true;
				}
				if (rs.getString("M_wake_turb")!=null) {
					if (!flgr) {rpl+="\n";flgr=true;}
					rpl+="/"+rs.getString("M_wake_turb");
					flgr=true;
				}
				
				//type10a and b
				if (rs.getString("type10a")!=null) {
					rpl+="-"+rs.getString("type10a");
				}
				if (rs.getString("type10b")!=null) {
					rpl+="/"+rs.getString("type10b");
				}
				
				//type13
				flgr=false;
				if (rs.getString("N_dep_ad")!=null) {
					rpl+="\n-"+rs.getString("N_dep_ad");
					flgr=true;
				}
				if (rs.getString("N_time_dep")!=null) {
					rpl+=rs.getString("N_time_dep");
				}
				
				//type15
				if (rs.getString("O_speed")!=null) {
					rpl+="\n-"+rs.getString("O_speed");
				}
				if (rs.getString("O_level")!=null) {
					rpl+=rs.getString("O_level");
				}
				if (rs.getString("O_route")!=null) {
					rpl+=" "+rs.getString("O_route");
				}
				
				//type16
				if (rs.getString("P_dest_ad")!=null) {
					rpl+="\n-"+rs.getString("P_dest_ad");
				}
				if (rs.getString("P_total_eet")!=null) {
					rpl+=rs.getString("P_total_eet");
				}
				if (rs.getString("P_alt_ad1")!=null) {
					rpl+=" "+rs.getString("P_alt_ad1");
				}
				if (rs.getString("P_alt_ad2")!=null) {
					rpl+=" "+rs.getString("P_alt_ad2");
				}
				
				//type18
				if (rs.getString("Q_remarks")!=null) {
					if (!rs.getString("Q_remarks").isEmpty())
					rpl+="\n-"+rs.getString("Q_remarks");
					else rpl+="\n-0";
				}
				else rpl+="\n-0";
				
				rpl+=")";
			}
			rs.close();
		}
	}
	
	void prosesExeReject(Statement stmt,boolean hasilExe,int id) throws SQLException {
		if (!hasilExe) {
			System.out.println("not hasilExe");
			int updateCount=stmt.getUpdateCount();
			System.out.println(updateCount);
		} else {
			ResultSet rs=stmt.getResultSet();
			reject="";
			rejectATS="";
			rejectNOTAM="";
			rejectMETEO="";
			while (rs.next()) {
				if (rs.getString("priority")!=null) {
					reject+=rs.getString("priority");
				}
				boolean flg=false;
				for (int iCnt=1;iCnt<22;iCnt++) {
					String sDest="destination";
					sDest+=Integer.toString(iCnt);
					if (rs.getString(sDest)!=null) {
						if (rs.getString(sDest).compareTo("")!=0) {
							reject+=" ";
							reject+=rs.getString(sDest);
							if ((iCnt==7) || (iCnt==14)) reject+="\n";
						}
					}
				}
				reject+="\n";
				if (rs.getString("filing_time")!=null) {reject+=rs.getString("filing_time");reject+=" ";}
				if (rs.getString("originator")!=null) reject+=rs.getString("originator");
				if (rs.getString("ori_ref")!=null) {reject+=" ";reject+=rs.getString("ori_ref");}
				reject+="\n";
				if (rs.getString("origin_message")!=null) reject+=rs.getString("origin_message");
			}
			if (id==1) rejectATS=reject;
			else if (id==2) rejectNOTAM=reject;
			else if (id==3) rejectMETEO=reject;
		}
	}

