				if (part_nr == null){part_nr=""; }
				if (ref_ntm_id_serie == null){ref_ntm_id_serie=""; }
				if (ref_ntm_id_sequence == null){ref_ntm_id_sequence=""; }
				if (ref_ntm_id_years == null){ref_ntm_id_years=""; }
				if (ref_part == null){ref_part=""; }
				if (ref_part_nr == null){ref_part_nr=""; }
				if (fir == null){fir=""; }
				if (code23 == null){code23=""; }
				if (code45 == null){code45=""; }
				if (trafic == null){trafic=""; }
