	//******************************** PROSES EXE LOGIN ***********************************
	void prosesLOGIN(Statement stmt,boolean hasilExe) throws SQLException {
		if (!hasilExe) {
			System.out.println("not hasilExe");
			int updateCount = stmt.getUpdateCount();
			System.out.println(updateCount);
		} else {
			ResultSet rs = stmt.getResultSet();
			while (rs.next()) {
				username = rs.getString("user_login"); if (username == null) { username=""; }
				password = rs.getString("password_login"); if (password == null) { password=""; }
			}
		}
	}
	
